package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

public class GsonTest {

  @Test
  public void testNewBuilder() {
    Gson gson = new Gson();
    GsonBuilder builder = gson.newBuilder();
    assertNotNull(builder);

    try {
      Field field = null;
      Class<?> clazz = builder.getClass();

      // The field is named 'gson' in GsonBuilder, but in recent versions it might be 'original' or something else.
      // Also check for 'gson' field in the enclosing class if builder is an anonymous class.
      while (clazz != null) {
        try {
          field = clazz.getDeclaredField("gson");
          break;
        } catch (NoSuchFieldException e) {
          try {
            field = clazz.getDeclaredField("original");
            break;
          } catch (NoSuchFieldException ex) {
            clazz = clazz.getSuperclass();
          }
        }
      }

      // If still not found, try to find a field of type Gson in builder's declared fields as a fallback
      if (field == null) {
        clazz = builder.getClass();
        while (clazz != null) {
          for (Field f : clazz.getDeclaredFields()) {
            if (f.getType() == Gson.class) {
              field = f;
              break;
            }
          }
          if (field != null) break;
          clazz = clazz.getSuperclass();
        }
      }

      assertNotNull(field, "Field 'gson' or 'original' not found in GsonBuilder class hierarchy");
      field.setAccessible(true);
      Gson innerGson = (Gson) field.get(builder);
      assertSame(gson, innerGson);
    } catch (IllegalAccessException e) {
      fail("Reflection failed: " + e.getMessage());
    }
  }
}
